// Generated by hand. Sets up Claude's own memory space inside your vault —
// decisions, research, daily notes — and optionally makes it Claude's main
// memory on this computer, across every project, not just this one.

import { promises as fs } from 'node:fs';
import path from 'node:path';
import os from 'node:os';

export const definition = {
  id: 'obsidian-brainstem',
  name: 'Obsidian Brainstem Setup',
  description:
    "Gives Claude its own notes inside your vault — memories, decisions, research, a daily log — so it can remember things across sessions instead of starting over each time. You choose whether to make this Claude's main memory on this computer (every project, every session) or just set up the folders for now.",
  version: '1.0.0',
  inputs: [
    {
      name: 'vaultPath',
      type: 'text',
      label: 'Claude memory vault folder',
      description: 'Full path to the folder where Claude keeps its own notes. This should be a different folder than your Wiki vault, so the two don\'t mix.',
      required: true,
    },
    {
      name: 'activateMemory',
      type: 'boolean',
      label: "Make this Claude's main memory on this computer",
      description: "If checked, Claude will check this vault before doing substantial work on ANY project on this machine — not just this one. You can turn this off later.",
      required: false,
    },
    {
      name: 'dryRun',
      type: 'boolean',
      label: 'Preview only (don’t create or change anything yet)',
      description: 'Check this to see what would happen without touching your files or settings.',
      required: false,
    },
  ],
};

const FOLDERS = ['Memory', 'Daily', 'Decisions', 'Research', 'Projects', '_bench'];

const README = `# Claude

This is Claude's own space — notes it writes to remember things across sessions.

- **Memory/** — durable facts, preferences, how-we-work notes.
- **Daily/** — a running log of what happened in each session.
- **Decisions/** — why a nontrivial call got made, so it doesn't get re-argued.
- **Research/** — findings from deeper investigations.
- **Projects/** — status notes for ongoing work.
- **_bench/** — maintenance and benchmark logs Claude writes during upkeep.

Claude writes only inside this folder. It never edits anything outside \`Claude/\`.
`;

const MARKER_START = '<!-- obsidian-brainstem:start -->';
const MARKER_END = '<!-- obsidian-brainstem:end -->';

function directiveBlock(vaultPath) {
  return `${MARKER_START}
Use the Obsidian vault at ${vaultPath} as primary cross-project memory.
Before substantial work on any project, read ${vaultPath}/Claude/README.md
and check relevant notes under ${vaultPath}/Claude/ for prior memory,
decisions, and research. Write new memory/decisions/research there by default.
${MARKER_END}
`;
}

export async function run(input, _ctx) {
  const vaultPath = String(input.vaultPath || '').trim();
  if (!vaultPath) return { ok: false, error: 'vaultPath is required' };
  const dryRun = !!input.dryRun;
  const activateMemory = !!input.activateMemory;

  const created = [];
  const alreadyExisted = [];

  for (const folder of FOLDERS) {
    const dir = path.join(vaultPath, 'Claude', folder);
    if (dryRun) {
      created.push(dir);
      continue;
    }
    let existed = true;
    try {
      await fs.access(dir);
    } catch {
      existed = false;
    }
    await fs.mkdir(dir, { recursive: true });
    (existed ? alreadyExisted : created).push(dir);
  }

  const readmePath = path.join(vaultPath, 'Claude', 'README.md');
  let readmeWritten = false;
  if (dryRun) {
    readmeWritten = true;
  } else {
    try {
      await fs.access(readmePath);
    } catch {
      await fs.writeFile(readmePath, README, 'utf8');
      readmeWritten = true;
    }
  }

  let directiveApplied = false;
  let directiveSkippedReason = null;
  if (activateMemory) {
    if (dryRun) {
      directiveApplied = true;
    } else {
      const claudeMdPath = path.join(os.homedir(), '.claude', 'CLAUDE.md');
      let existing = '';
      try {
        existing = await fs.readFile(claudeMdPath, 'utf8');
      } catch {
        existing = '';
      }
      if (existing.includes(MARKER_START)) {
        directiveSkippedReason = 'already activated on this machine';
      } else {
        const updated = existing.trimEnd() + '\n\n' + directiveBlock(vaultPath);
        await fs.mkdir(path.dirname(claudeMdPath), { recursive: true });
        await fs.writeFile(claudeMdPath, updated, 'utf8');
        directiveApplied = true;
      }
    }
  }

  return {
    ok: true,
    dryRun,
    vaultPath,
    foldersPlanned: FOLDERS,
    created,
    alreadyExisted,
    readmeWritten,
    activateMemory,
    directiveApplied,
    directiveSkippedReason,
  };
}

export const tests = [
  {
    name: 'dry run reports planned folders and directive without touching disk',
    input: { vaultPath: 'C:/Example/ClaudeVault', activateMemory: true, dryRun: true },
    expect: {
      ok: true,
      dryRun: true,
      vaultPath: 'C:/Example/ClaudeVault',
      foldersPlanned: ['Memory', 'Daily', 'Decisions', 'Research', 'Projects', '_bench'],
      created: [
        'C:\\Example\\ClaudeVault\\Claude\\Memory',
        'C:\\Example\\ClaudeVault\\Claude\\Daily',
        'C:\\Example\\ClaudeVault\\Claude\\Decisions',
        'C:\\Example\\ClaudeVault\\Claude\\Research',
        'C:\\Example\\ClaudeVault\\Claude\\Projects',
        'C:\\Example\\ClaudeVault\\Claude\\_bench',
      ],
      alreadyExisted: [],
      readmeWritten: true,
      activateMemory: true,
      directiveApplied: true,
      directiveSkippedReason: null,
    },
  },
  {
    name: 'missing vaultPath fails fast',
    input: {},
    expect: { ok: false, error: 'vaultPath is required' },
  },
];
